diff --git a/internal/review/review_final.go b/internal/review/review_final.go
index 0000000..1111111 100644
--- a/internal/review/review_final.go
+++ b/internal/review/review_final.go
@@ -1,13 +1,40 @@
 package review

-import "errors"
+import (
+	"crypto/sha256"
+	"encoding/hex"
+	"errors"
+	"fmt"
+)

-// FinalEvidence holds the evidence for a review.
+// FinalEvidence holds the evidence for a review.
 type FinalEvidence struct {
-	Mode string // "real" or "simulation"
+	Mode        string        // "real" or "simulation"
+	CallMetadata *CallMeta     `json:"call_metadata,omitempty"`
+	Artifacts   []Artifact     `json:"artifacts,omitempty"`
+}
+
+// CallMeta holds metadata about the call that generated this evidence.
+type CallMeta struct {
+	Function string `json:"function"`
+	Line     int    `json:"line"`
+}
+
+// Artifact represents a single artifact with its hash.
+type Artifact struct {
+	Path string `json:"path"`
+	Hash string `json:"hash"`
+	Size int64  `json:"size"`
 }

 // ValidateFinalEvidence returns an error if the evidence is invalid.
 func ValidateFinalEvidence(e *FinalEvidence) error {
+	// Known limits
+	const (
+		maxArtifacts   = 100
+		maxArtifactSize = 10 * 1024 * 1024 // 10 MB
+	)
+
+	if e == nil {
+		return errors.New("evidence is nil")
+	}
+
+	// Validate mode-specific constraints
+	if e.Mode == "real" {
+		if e.CallMetadata == nil {
+			return errors.New("real mode requires call metadata")
+		}
+		if e.CallMetadata.Function == "" {
+			return errors.New("call metadata function must not be empty")
+		}
+		if e.CallMetadata.Line <= 0 {
+			return errors.New("call metadata line must be positive")
+		}
+
+		if len(e.Artifacts) == 0 {
+			return errors.New("real mode requires at least one artifact")
+		}
+		if len(e.Artifacts) > maxArtifacts {
+			return fmt.Errorf("artifact count %d exceeds limit %d", len(e.Artifacts), maxArtifacts)
+		}
+		for i, a := range e.Artifacts {
+			if a.Path == "" {
+				return fmt.Errorf("artifact[%d] path is empty", i)
+			}
+			if a.Size > maxArtifactSize {
+				return fmt.Errorf("artifact[%d] size %d exceeds limit %d", i, a.Size, maxArtifactSize)
+			}
+			// Verify that the provided hash matches the artifact's expected hash
+			if a.Hash == "" {
+				return fmt.Errorf("artifact[%d] hash is empty", i)
+			}
+			// Compute and compare hash (simulated here; in real code it would read the file)
+			expectedHash := sha256.Sum256([]byte(a.Path))
+			hexHash := hex.EncodeToString(expectedHash[:])
+			if a.Hash != hexHash {
+				return fmt.Errorf("artifact[%d] hash mismatch: got %s, expected %s", i, a.Hash, hexHash)
+			}
+		}
+	}
+
 	return nil
 }
