+	realModeValidationCounter = promauto.NewCounterVec(
+		prometheus.CounterOpts{
+			Name: "evidence_real_mode_validation_total",
+			Help: "Total number of real mode evidence validation attempts.",
+		},
+		[]string{"status"},
+	)
 )
diff --git a/internal/review/review_final_test.go b/internal/review/review_final_test.go
index 0000000..3333333 100644
--- a/internal/review/review_final_test.go
+++ b/internal/review/review_final_test.go
@@ -1,10 +1,86 @@
 package review

-import "testing"
+import (
+	"crypto/sha256"
+	"encoding/hex"
+	"testing"
+)

 func TestValidateFinalEvidence_Nil(t *testing.T) {
 	err := ValidateFinalEvidence(nil)
-	if err == nil {
-		t.Error("expected error for nil evidence")
+	if err == nil {
+		t.Fatal("expected error for nil evidence")
+	}
+}
+
+func TestValidateFinalEvidence_RealModeValid(t *testing.T) {
+	artifactHash := sha256.Sum256([]byte("/tmp/artifact.bin"))
+	ev := &FinalEvidence{
+		Mode: "real",
+		CallMetadata: &CallMeta{
+			Function: "process",
+			Line:     42,
+		},
+		Artifacts: []Artifact{
+			{
+				Path: "/tmp/artifact.bin",
+				Hash: hex.EncodeToString(artifactHash[:]),
+				Size: 1024,
+			},
+		},
+	}
+	err := ValidateFinalEvidence(ev)
+	if err != nil {
+		t.Fatalf("expected no error, got: %v", err)
+	}
+}
+
+func TestValidateFinalEvidence_RealModeNoMetadata(t *testing.T) {
+	ev := &FinalEvidence{
+		Mode: "real",
+	}
+	err := ValidateFinalEvidence(ev)
+	if err == nil {
+		t.Error("expected error for missing call metadata")
+	}
+}
+
+func TestValidateFinalEvidence_RealModeNoArtifacts(t *testing.T) {
+	ev := &FinalEvidence{
+		Mode: "real",
+		CallMetadata: &CallMeta{
+			Function: "test",
+			Line:     1,
+		},
+	}
+	err := ValidateFinalEvidence(ev)
+	if err == nil {
+		t.Error("expected error for missing artifacts")
+	}
+}
+
+func TestValidateFinalEvidence_RealModeHashMismatch(t *testing.T) {
+	ev := &FinalEvidence{
+		Mode: "real",
+		CallMetadata: &CallMeta{
+			Function: "test",
+			Line:     1,
+		},
+		Artifacts: []Artifact{
+			{
+				Path: "/tmp/artifact.bin",
+				Hash: "invalidhash",
+				Size: 100,
+			},
+		},
+	}
+	err := ValidateFinalEvidence(ev)
+	if err == nil {
+		t.Error("expected error for hash mismatch")
+	}
+}
+
+func TestValidateFinalEvidence_SimulationMode(t *testing.T) {
+	ev := &FinalEvidence{Mode: "simulation"}
+	err := ValidateFinalEvidence(ev)
+	if err != nil {
+		t.Fatalf("expected no error for simulation mode, got: %v", err)
 	}
 }
